Here's a modern MSTest 3.x approach for testing `DataFetcher` with proper timeout and cancellation handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // Helper: build a DataFetcher with a fake handler
    private static DataFetcher CreateFetcher(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        var client = new HttpClient(new FakeHandler(handler));
        return new DataFetcher(client);
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsBody()
    {
        var fetcher = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var fetcher = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.NotFound)));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)] // guard against hangs
    public async Task FetchAsync_SlowResponse_CompletesWithinTimeout()
    {
        var fetcher = CreateFetcher(async (_, ct) =>
        {
            await Task.Delay(100, ct); // simulate latency
            return new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("delayed")
            };
        });

        // Pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("delayed", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        using var cts = new CancellationTokenSource();
        var fetcher = CreateFetcher(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct); // blocks until cancelled
            return new HttpResponseMessage();        // never reached
        });

        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_CancelledDuringRequest_ThrowsTaskCanceledException()
    {
        using var cts = new CancellationTokenSource();
        var fetcher = CreateFetcher(async (_, ct) =>
        {
            // Simulate a request that gets cancelled mid-flight
            await Task.Delay(TimeSpan.FromSeconds(2), ct);
            return new HttpResponseMessage();
        });

        cts.CancelAfter(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    // Minimal DelegatingHandler replacement — no mocking library needed
    private sealed class FakeHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => handler(request, cancellationToken);
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(5000)]` + pass `_testContext.CancellationToken` into the async call |
| **Pre-cancelled token** | `cts.Cancel()` before calling, asserts `TaskCanceledException` |
| **Mid-flight cancellation** | `cts.CancelAfter(50ms)` with a slow handler |
| **No mocking library** | `FakeHandler` extends `HttpMessageHandler` directly |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Constructor injection** | `TestContext` injected via constructor, enabling `readonly` |

The critical detail: always flow `TestContext.CancellationToken` into your async calls in tests with `[Timeout]`. Without it, a hung test won't be cancelled — the timeout fires but has no way to stop the work.
